const slugify = (s) => s.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 48)

function trimJson(obj, depth = 0) {
  if (obj == null) return obj
  if (typeof obj !== 'object') return obj
  if (Array.isArray(obj)) return obj.slice(0, 2).map((x) => trimJson(x, depth + 1))
  const out = {}
  let n = 0
  for (const [k, v] of Object.entries(obj)) {
    if (n++ >= 8) break
    out[k] = typeof v === 'object' ? trimJson(v, depth + 1) : v
  }
  return out
}

function findHint(c) {
  const hay = `${c.name} ${c.docsUrl} ${c.description}`
  for (const h of PROBE_HINTS) {
    if (h.match.test(hay)) return { ...h, docsUrl: c.docsUrl || h.baseUrl }
  }
  return null
}

async function probe(url) {
  const ctrl = new AbortController()
  const t = setTimeout(() => ctrl.abort(), 8000)
  const t0 = performance.now()
  try {
    const res = await fetch(url, {
      signal: ctrl.signal,
      redirect: 'follow',
      headers: {
        'user-agent': UA,
        origin: ORIGIN,
        accept: 'application/json',
      },
    })
    const text = await res.text()
    const latencyMs = Math.round(performance.now() - t0)
    let json
    try { json = JSON.parse(text) } catch { json = null }
    const cors = res.headers.get('access-control-allow-origin')
    return {
      httpStatus: res.status,
      latencyMs,
      json,
      corsObserved: cors === '*' || cors === ORIGIN ? true : cors ? true : false,
    }
  } catch (e) {
    return { httpStatus: 0, latencyMs: 0, json: null, corsObserved: null, error: String(e) }
  } finally {
    clearTimeout(t)
  }
}

const verified = []
const skipped = []

for (const hint of PROBE_HINTS) {
  if (verified.length >= LIMIT) break
  let host
  try { host = new URL(hint.baseUrl).hostname.replace(/^www\./, '') } catch { continue }
  if (seedHosts.has(host)) {
    skipped.push({ name: hint.name, reason: 'already in seed' })
    continue
  }

  const url = hint.baseUrl.replace(/\/+$/, '') + hint.sampleEndpoint
  const result = await probe(url)
  if (result.httpStatus !== 200 || !result.json) {
    skipped.push({ name: hint.name, reason: `probe failed HTTP ${result.httpStatus || 'err'} ${result.error || ''}`.trim() })
    continue
  }

  verified.push({
    name: hint.name,
    slug: slugify(hint.name),
    emoji: hint.emoji || '🔌',
    tagline: hint.tagline,
    description: hint.description,
    sourceCategory: hint.sourceCategory,
    docsUrl: hint.docsUrl || hint.baseUrl,
    baseUrl: hint.baseUrl.replace(/\/+$/, ''),
    sampleEndpoint: hint.sampleEndpoint.startsWith('/') ? hint.sampleEndpoint : '/' + hint.sampleEndpoint,
    latencyMs: result.latencyMs,
    corsObserved: result.corsObserved,
    httpStatus: 200,
    sampleJson: trimJson(result.json),
    freeTier: 'Free — limits not published',
    rateLimit: 'Unpublished',
    dataLicense: 'Unverified',
    commercialUse: 'unclear',
  })
  process.stdout.write(`  ✓ ${verified[verified.length - 1].slug}\n`)
}

const out = { batch: batchNo, verified, skipped: skipped.slice(0, 80) }
const outPath = `${IMPORT_DIR}batch-${String(batchNo).padStart(2, '0')}.json`
writeFileSync(outPath, JSON.stringify(out, null, 2) + '\n')
console.log(`\nbatch ${batchNo}: ${verified.length} verified, ${skipped.length} skipped → ${outPath}`)
